const PROCESSING_FEE = 5;
const SWORD_BASE_PREMIUM = 110;

const calculatePremium = (items: Array<Record<string, unknown>>): number => {
  if (items.length === 0) return PROCESSING_FEE;
  return SWORD_BASE_PREMIUM + PROCESSING_FEE;
};

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const results = scenario.steps.map((step) => ({
    premium: calculatePremium(step.items ?? []),
  }));
  return { results };
};
